<script setup>
import { computed, onMounted, ref } from 'vue'
import AuditService from '../../services/AuditService'

const rows = ref([]); const users = ref([]); const total = ref(0); const loading = ref(false); const error = ref(''); const page = ref(1)
const filters = ref({ usuarioId: '', modulo: '', accion: '', fechaDesde: '', fechaHasta: '' })
const modules = ['usuario', 'vacante', 'postulacion', 'documento', 'catalogo', 'empresa', 'reportes', 'privacidad', 'sistema']
const actions = ['inicio_sesion', 'cierre_sesion', 'usuario_creado', 'usuario_actualizado', 'usuario_estado_actualizado', 'vacante_borrador_creado', 'vacante_actualizada', 'vacante_publicada', 'vacante_cerrada', 'consulta_postulacion', 'descarga_documento', 'cambio_estado_administrativo', 'exportacion_reporte', 'limpieza_conservacion_gdpr']
const totalPages = computed(() => Math.max(Math.ceil(total.value / 25), 1))
const label = value => (value || '—').replaceAll('_', ' ')
const date = value => value ? new Date(value).toLocaleString('es-ES', { dateStyle: 'short', timeStyle: 'short' }) : '—'
async function load () { loading.value = true; error.value = ''; try { const data = await AuditService.list({ ...filters.value, page: page.value, pageSize: 25 }); rows.value = data.rows; users.value = data.users; total.value = data.total } catch (e) { error.value = e.message || 'No fue posible cargar la auditoría.' } finally { loading.value = false } }
function apply () { page.value = 1; load() }
function clear () { filters.value = { usuarioId: '', modulo: '', accion: '', fechaDesde: '', fechaHasta: '' }; apply() }
onMounted(load)
</script>

<template><div><header class="mb-7 flex flex-col gap-4 xl:flex-row xl:items-end xl:justify-between"><div><p class="text-sm font-semibold text-brand-600">Control y trazabilidad</p><h2 class="mt-1 font-display text-2xl font-bold text-stone-900">Auditoría</h2><p class="mt-1 text-sm text-stone-500">Registro inmutable de acciones relevantes del sistema.</p></div><p class="rounded-xl bg-stone-100 px-4 py-2 text-sm font-semibold text-stone-600">{{ total }} eventos registrados</p></header><section class="card border border-stone-100 p-5 shadow-sm"><div class="grid gap-3 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5"><label class="filter-label">Usuario<select v-model="filters.usuarioId" class="input-field mt-1"><option value="">Todos</option><option v-for="user in users" :key="user.id" :value="user.id">{{ user.nombres }} {{ user.apellidos }}</option></select></label><label class="filter-label">Módulo<select v-model="filters.modulo" class="input-field mt-1"><option value="">Todos</option><option v-for="module in modules" :key="module" :value="module">{{ label(module) }}</option></select></label><label class="filter-label">Acción<select v-model="filters.accion" class="input-field mt-1"><option value="">Todas</option><option v-for="action in actions" :key="action" :value="action">{{ label(action) }}</option></select></label><label class="filter-label">Desde<input v-model="filters.fechaDesde" type="date" class="input-field mt-1" /></label><label class="filter-label">Hasta<input v-model="filters.fechaHasta" type="date" class="input-field mt-1" /></label></div><div class="mt-4 flex gap-2"><button type="button" class="btn-primary px-4 py-2 text-sm" :disabled="loading" @click="apply">Aplicar filtros</button><button type="button" class="btn-secondary px-4 py-2 text-sm" :disabled="loading" @click="clear">Limpiar</button></div></section><p v-if="error" class="mt-5 rounded-xl border border-red-100 bg-red-50 p-4 text-sm text-red-700">{{ error }}</p><section class="card mt-6 overflow-hidden border border-stone-100 shadow-sm"><div v-if="loading" class="py-16 text-center text-sm text-stone-400">Cargando registros de auditoría...</div><div v-else-if="!rows.length" class="py-16 text-center text-sm text-stone-400">No hay eventos que coincidan con los filtros.</div><div v-else class="overflow-x-auto"><table class="min-w-full text-left text-sm"><thead class="bg-stone-50 text-xs uppercase tracking-wide text-stone-400"><tr><th class="px-4 py-3">Fecha</th><th class="px-4 py-3">Usuario</th><th class="px-4 py-3">Acción</th><th class="px-4 py-3">Módulo</th><th class="px-4 py-3">Descripción</th></tr></thead><tbody><tr v-for="row in rows" :key="row.id" class="border-t border-stone-100"><td class="whitespace-nowrap px-4 py-3 text-stone-500">{{ date(row.fecha_hora) }}</td><td class="px-4 py-3 font-semibold text-stone-700">{{ row.actor ? `${row.actor.nombres} ${row.actor.apellidos}` : 'Sistema' }}</td><td class="px-4 py-3"><span class="rounded-full bg-brand-50 px-2.5 py-1 text-xs font-semibold text-brand-700">{{ label(row.accion) }}</span></td><td class="px-4 py-3 capitalize text-stone-600">{{ label(row.modulo) }}</td><td class="max-w-md px-4 py-3 text-stone-600">{{ row.descripcion || row.metadata?.descripcion || 'Evento registrado por el sistema.' }}</td></tr></tbody></table></div><footer class="flex items-center justify-between border-t border-stone-100 px-4 py-3 text-sm text-stone-500"><button type="button" class="btn-secondary px-3 py-1.5 text-xs" :disabled="page === 1" @click="page--; load()">Anterior</button><span>Página {{ page }} de {{ totalPages }}</span><button type="button" class="btn-secondary px-3 py-1.5 text-xs" :disabled="page === totalPages" @click="page++; load()">Siguiente</button></footer></section></div></template>

<style scoped>.filter-label { @apply text-xs font-semibold text-stone-600; }</style>
